void applyWebConfig() {
 PX_threshold = myConfig.currentThreshold;
}

void loadWebConfig() {
 if (LittleFS.exists(WEB_CONFIG_FILE)) {
 File f = LittleFS.open(WEB_CONFIG_FILE, "r");
 if (f) {
 size_t bytesRead = f.read((uint8_t*)&myConfig, sizeof(WebConfig));
 f.close();
 if (bytesRead == sizeof(WebConfig)) {
 applyWebConfig();
 return;
 }
 }
 }

 memset(&myConfig, 0, sizeof(WebConfig));
 strncpy(myConfig.wifi_ssid, WIFI_SSID_DEFAULT, sizeof(myConfig.wifi_ssid) - 1);
 strncpy(myConfig.wifi_pass, WIFI_PASS_DEFAULT, sizeof(myConfig.wifi_pass) - 1);
 strncpy(myConfig.admin_pass, ADMIN_PASS_DEFAULT, sizeof(myConfig.admin_pass) - 1);
 strncpy(myConfig.n8n_webhook, N8N_WEBHOOK_DEFAULT, sizeof(myConfig.n8n_webhook) - 1);
 myConfig.currentThreshold = 4.0;
 myConfig.ledDisabled = false; 

 strncpy(myConfig.company_name, "IIoT", sizeof(myConfig.company_name) - 1);
 strncpy(myConfig.header_desc, "укажите имя устройства", sizeof(myConfig.header_desc) - 1);
 strncpy(myConfig.device_type, "Основное", sizeof(myConfig.device_type) - 1); 
 strncpy(myConfig.inv_number, "не указан", sizeof(myConfig.inv_number) - 1); 

 strncpy(myConfig.header_color, "#ed1c24", sizeof(myConfig.header_color) - 1); 
 strncpy(myConfig.menu_color, "#000000", sizeof(myConfig.menu_color) - 1); 
 strncpy(myConfig.bg_color, "#ffffff", sizeof(myConfig.bg_color) - 1); 

 saveWebConfig();
}

void saveWebConfig() {
 File f = LittleFS.open(WEB_CONFIG_FILE, "w");
 if (f) {
 f.write((uint8_t*)&myConfig, sizeof(WebConfig));
 f.close();
 applyWebConfig();
 }
}

void initStorage() {
 if (!LittleFS.begin()) {
 LittleFS.format();
 LittleFS.begin();
 }
 loadWebConfig();
}

bool isAuthenticated() {
 if (!server.hasHeader("Cookie")) return false;
 String cookie = server.header("Cookie");
 String targetAuth = "auth=" + String(myConfig.admin_pass);
 int index = cookie.indexOf(targetAuth);
 if (index == -1) return false;
 char nextChar = cookie.charAt(index + targetAuth.length());
 if (nextChar == '\0' || nextChar == ';' || nextChar == ' ') return true;
 return false;
}

