void handleLogin(const String& targetUrl, const String& activePage) {
 if (isAuthenticated()) { server.sendHeader("Location", targetUrl); server.send(303); return; }
 if (server.hasArg("password") && server.arg("password") == String(myConfig.admin_pass)) {
 server.sendHeader("Set-Cookie", "auth=" + String(myConfig.admin_pass) + "; Path=/; HttpOnly");
 server.sendHeader("Location", targetUrl); server.send(303); return;
 }
 String html = getHeaderHTML("Авторизация", activePage, false); html.reserve(800);
 html += F("<div class='page-title'>Доступ ограничен. Введите пароль администратора:</div>");
 if (server.hasArg("password")) html += F("<p class='error-msg'>Неверный пароль!</p>");
 html += F("<form method='POST' action='"); html += targetUrl;
 html += F("'>Пароль доступа: <input type='password' name='password'><input type='submit' value='Войти'></form>");
 html += getFooterHTML(); server.send(200, "text/html", html);
}

