void handleAccess() {
 if (!isAuthenticated()) { handleLogin("/access", "access"); return; }
 if (server.hasArg("reboot")) {
 server.sendHeader("Refresh", "10; url=/"); 
 String html = getHeaderHTML("Перезагрузка", "access", false);
 html += F("<div class='page-title'>Перезагрузка...</div><p>Устройство перезапускается...</p>");
 html += getFooterHTML(); server.send(200, "text/html", html);
 delay(1000); ESP.restart(); return;
 }

 if (server.hasArg("ssid") && server.hasArg("pass")) {
 server.arg("ssid").toCharArray(myConfig.wifi_ssid, sizeof(myConfig.wifi_ssid));
 server.arg("pass").toCharArray(myConfig.wifi_pass, sizeof(myConfig.wifi_pass));
 saveWebConfig();
 String html = getHeaderHTML("Настройки сохранены", "access", false);
 html += F("<div class='page-title'>Параметры сети изменены!</div><p>Устройство перезагружается...</p>");
 html += getFooterHTML(); server.send(200, "text/html", html);
 delay(1000); ESP.restart(); return;
 }

 if (server.hasArg("admin_p")) { server.arg("admin_p").toCharArray(myConfig.admin_pass, sizeof(myConfig.admin_pass)); saveWebConfig(); }

 String html = getHeaderHTML("Доступ", "access", false); html.reserve(1600);
 html += F("<div class='page-title'>Администрирование и сеть</div><form method='POST' action='/access'>");
 html += F("Имя сети Wi-Fi (SSID): <input type='text' name='ssid' value='"); html += String(myConfig.wifi_ssid);
 html += F("'>Пароль Wi-Fi: <input type='password' name='pass' value='"); html += String(myConfig.wifi_pass);
 html += F("'><br>Пароль администратора: <input type='password' name='admin_p' value='"); html += String(myConfig.admin_pass);
 html += F("'><input type='submit' value='Сохранить параметры'></form><br><hr><br><form method='POST' action='/access'><input type='hidden' name='reboot' value='true'>");
 html += F("<input type='submit' value='Перезагрузить устройство' style='background-color:#ed1c24;'></form>");
 html += getFooterHTML(); server.send(200, "text/html", html);
}

