void saveEventToBuffer(int markerType, unsigned long duration) {
 File f = LittleFS.open(BUFFER_FILE, "a");
 if (!f) return;
 LogEntry entry;
 entry.markerType = markerType;
 entry.duration = duration;
 f.write((uint8_t*)&entry, sizeof(LogEntry));
 f.close();
}

bool sendWebhook(int markerType, unsigned long duration) {
 if (WiFi.status() != WL_CONNECTED) return false;
 HTTPClient http;
 http.setTimeout(3000);
 if (http.begin(wifiClient, myConfig.n8n_webhook)) {
 http.addHeader(F("Content-Type"), F("application/json"));

 // Четкое разделение режимов: PX (1) и ONLINE (3)
 String modeStr;
 unsigned long currentDuration = duration;

 if (markerType == 1) {
 modeStr = F("PX"); // Окончание рабочего хода
 } else if (markerType == 3) {
 modeStr = F("ONLINE"); // Устройство вышло на связь
 currentDuration = 0;
 } else {
 modeStr = F("STOP"); // Защитный флаг для буфера
 currentDuration = 0;
 }

 // Сборка JSON строго с англоязычными ключами по ТЗ
 String jsonPayload; jsonPayload.reserve(300);
 jsonPayload += F("{\"mac_address\":\""); jsonPayload += WiFi.macAddress();
 jsonPayload += F("\",\"device_type\":\""); jsonPayload += String(myConfig.device_type); 
 jsonPayload += F("\",\"inv_number\":\""); jsonPayload += String(myConfig.inv_number); 
 jsonPayload += F("\",\"identifier\":\""); jsonPayload += String(myConfig.header_desc); 
 jsonPayload += F("\",\"mode\":\""); jsonPayload += modeStr; 
 jsonPayload += F("\",\"duration\":"); jsonPayload += String(currentDuration);
 jsonPayload += F("}");

 int httpResponseCode = http.POST(jsonPayload);
 http.end();
 return (httpResponseCode >= 200 && httpResponseCode < 300);
 }
 return false;
}

void processOfflineBuffer() {
 if (!LittleFS.exists(BUFFER_FILE)) return;
 File f = LittleFS.open(BUFFER_FILE, "r");
 if (!f) return;
 if (f.size() / sizeof(LogEntry) == 0) { f.close(); LittleFS.remove(BUFFER_FILE); return; }

 bool allSent = true;
 size_t lastSuccessfulPosition = 0;
 while (f.available() >= sizeof(LogEntry)) {
 LogEntry entry;
 f.read((uint8_t*)&entry, sizeof(LogEntry));
 if (sendWebhook(entry.markerType, entry.duration)) {
 lastSuccessfulPosition = f.position();
 ESP.wdtFeed();
 delay(10);
 } else { allSent = false; break; }
 }
 f.close();

 if (allSent) {
 LittleFS.remove(BUFFER_FILE);
 } else if (lastSuccessfulPosition > 0) {
 File fSrc = LittleFS.open(BUFFER_FILE, "r");
 File fTmp = LittleFS.open(TEMP_FILE, "w");
 if (fSrc && fTmp) {
 fSrc.seek(lastSuccessfulPosition, SeekSet);
 while (fSrc.available() >= sizeof(LogEntry)) {
 LogEntry entry; fSrc.read((uint8_t*)&entry, sizeof(LogEntry));
 fTmp.write((uint8_t*)&entry, sizeof(LogEntry));
 }
 }
 if (fSrc) fSrc.close(); if (fTmp) fTmp.close();
 LittleFS.remove(BUFFER_FILE); LittleFS.rename(TEMP_FILE, BUFFER_FILE);
 }
}

void handleWifiDisconnectBlink() {
 static unsigned long lastWifiBlink = 0;
 static bool toggleState = false;
 unsigned long currentMillis = millis();

 digitalWrite(ledBlue, HIGH);
 digitalWrite(ledGreen, HIGH);

 if (currentMillis - lastWifiBlink >= WIFI_BLINK_INTERVAL) {
 lastWifiBlink = currentMillis;
 toggleState = !toggleState;
 digitalWrite(ledRed, toggleState ? LOW : HIGH); 
 }
}

void setup() {
 Serial.begin(115200);
 delay(2500); 
 Serial.println();
 Serial.println(F("===================================="));
 Serial.println(F("[SYSTEM] Запуск системы мониторинга..."));
 Serial.println(F("===================================="));

 pinMode(ledBlue, OUTPUT);
 pinMode(ledGreen, OUTPUT);
 pinMode(ledRed, OUTPUT);

 digitalWrite(ledBlue, HIGH);
 digitalWrite(ledGreen, HIGH);
 digitalWrite(ledRed, HIGH);

 initStorage();
 emon1.current(sensorPin, calibrationK); 

 WiFi.mode(WIFI_STA);
 deviceName = "ESP12F_" + WiFi.macAddress();
 deviceName.replace(":", ""); 

 WiFi.begin(myConfig.wifi_ssid, myConfig.wifi_pass);

 server.collectHeaders("Cookie"); 

 server.on("/", HTTP_GET, handleRoot); server.on("/", HTTP_POST, handleRoot); 
 server.on("/sensor", HTTP_GET, handleSensor); server.on("/sensor", HTTP_POST, handleSensor);
 server.on("/n8n", HTTP_GET, handleN8N); server.on("/n8n", HTTP_POST, handleN8N);
 server.on("/style", HTTP_GET, handleStyle); server.on("/style", HTTP_POST, handleStyle); 
 server.on("/access", HTTP_GET, handleAccess); server.on("/access", HTTP_POST, handleAccess);
 server.on("/update", HTTP_GET, handleUpdatePage);

 httpUpdater.setup(&server, "/do_update");

 server.begin();

 // Защита от ложного старта: определяем статус станка на включении питания
 double startIrms = emon1.calcIrms(740);
 if (startIrms >= PX_threshold) {
 currentFlag = PX;
 pxStartTime = millis();
 } else {
 currentFlag = STOP;
 }

 ESP.wdtEnable(2000); 
}

void loop() {
 ESP.wdtFeed(); 
 server.handleClient(); 
 unsigned long currentMillis = millis();
 bool isConnected = (WiFi.status() == WL_CONNECTED);

 if (!isConnected) {
 handleWifiDisconnectBlink(); 
 wifiWasConnected = false;
 onlineSent = false; 
 } else {
 digitalWrite(ledRed, HIGH); 

 if (!wifiWasConnected) {
 Serial.print(F("[WIFI] Connected. IP: ")); Serial.print(WiFi.localIP());
 Serial.printf(" | Pass: %s\n", myConfig.admin_pass);
 wifiWasConnected = true;
 }
 if (!onlineSent) {
 if (sendWebhook(3, 0)) { // 3 = ONLINE
 onlineSent = true;
 processOfflineBuffer(); 
 }
 }

 if (myConfig.ledDisabled) {
 digitalWrite(ledBlue, HIGH);
 digitalWrite(ledGreen, HIGH);
 } else {
 digitalWrite(ledBlue, LOW); 
 digitalWrite(ledGreen, LOW); 
 }
 }

 if (currentMillis - lastMeasurementTime >= 500) {
 lastMeasurementTime = currentMillis;
 ESP.wdtFeed(); 

 server.handleClient();
 yield(); 

 double rawIrms = emon1.calcIrms(740); 

 yield(); 
 double cleanIrms = (rawIrms > noiseOffset) ? rawIrms : 0.0;
 currentRMS = cleanIrms; 

 State instantaneousState = (cleanIrms >= PX_threshold) ? PX : STOP;
 if (instantaneousState != currentFlag) {
 if (instantaneousState != targetState) {
 targetState = instantaneousState;
 stateChangeTimer = currentMillis; 
 } else if (currentMillis - stateChangeTimer >= DEBOUNCE_TIME) {

 // Нагрузка выключилась — отправляем пакет PX со временем работы
 if (instantaneousState == STOP && currentFlag == PX) {
 unsigned long durationSec = (currentMillis - pxStartTime) / 1000;
 currentFlag = STOP;
 if (!sendWebhook(1, durationSec)) {
 saveEventToBuffer(1, durationSec);
 onlineSent = false; 
 }
 } 
 // Нагрузка включилась — просто молча взводим внутренний таймер
 else if (instantaneousState == PX && currentFlag == STOP) {
 currentFlag = PX;
 pxStartTime = currentMillis; 
 }
 stateChangeTimer = 0; 
 }
 } else {
 targetState = currentFlag;
 stateChangeTimer = 0;
 }

 static unsigned long lastSerialLogTime = 0;
 if (currentMillis - lastSerialLogTime >= 5000) {
 lastSerialLogTime = currentMillis;
 Serial.printf("[MONITOR] Ток: %.2f A | %s | Wi-Fi: %s\n", 
 cleanIrms, (currentFlag == PX) ? "РАБОЧИЙ ХОД" : "СТОП", isConnected ? "ONLINE" : "OFFLINE");
 }
 }
}
